const cssContent = ".container{max-width:1200px;margin:0 auto;padding:0 20px}.app{min-height:100vh}.header{position:fixed;top:0;left:0;right:0;background:#fffffff2;-webkit-backdrop-filter:blur(10px);backdrop-filter:blur(10px);z-index:100;box-shadow:0 1px 3px #0000001a}.header .container{display:flex;justify-content:space-between;align-items:center;height:60px}.logo{font-size:20px;font-weight:700;color:#2563eb}.nav a{margin-left:24px;text-decoration:none;color:#374151;font-size:14px;transition:color .2s}.nav a:hover{color:#2563eb}.hero{padding:160px 0 120px;background:linear-gradient(135deg,#667eea,#764ba2);color:#fff;text-align:center}.hero h1{font-size:48px;font-weight:800;margin-bottom:20px;line-height:1.2}.hero .subtitle{font-size:20px;opacity:.9;margin-bottom:40px;max-width:600px;margin-left:auto;margin-right:auto}.cta-buttons{display:flex;gap:16px;justify-content:center}.btn{display:inline-block;padding:14px 32px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px;transition:all .2s}.btn-primary{background:#fff;color:#667eea}.btn-primary:hover{transform:translateY(-2px);box-shadow:0 10px 20px #0003}.btn-secondary{background:transparent;color:#fff;border:2px solid white}.btn-secondary:hover{background:#ffffff1a}.features,.cases,.contact{padding:80px 0}.features{background:#f9fafb}.features h2,.cases h2,.contact h2{text-align:center;font-size:36px;color:#111827;margin-bottom:48px}.feature-grid,.case-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(250px,1fr));gap:32px}.feature-card,.case-card{background:#fff;padding:32px;border-radius:12px;box-shadow:0 4px 6px #0000000d;transition:transform .2s,box-shadow .2s}.feature-card:hover,.case-card:hover{transform:translateY(-4px);box-shadow:0 12px 24px #0000001a}.feature-icon{font-size:40px;margin-bottom:16px}.feature-card h3,.case-card h3{font-size:18px;color:#111827;margin-bottom:12px}.feature-card p,.case-card p{color:#6b7280;font-size:14px;line-height:1.6}.cases{background:#fff}.case-card{border:1px solid #e5e7eb;box-shadow:none}.contact{background:linear-gradient(135deg,#667eea,#764ba2);color:#fff;text-align:center}.contact p{font-size:18px;margin-bottom:24px;opacity:.9}.contact .btn-primary{background:#fff;color:#667eea}.footer{background:#111827;color:#9ca3af;padding:24px 0;text-align:center}.footer p{font-size:14px}@media (max-width: 768px){.hero h1{font-size:32px}.hero .subtitle{font-size:16px}.cta-buttons{flex-direction:column;align-items:center}}\n";

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/' || path === '/index.html') {
      return new Response(indexHTML, {
        headers: { 'Content-Type': 'text/html;charset=UTF-8', 'Cache-Control': 'public, max-age=3600' }
      });
    }

    if (path.startsWith('/assets/') && path.endsWith('.js')) {
      return new Response(jsContent, {
        headers: { 'Content-Type': 'application/javascript;charset=UTF-8', 'Cache-Control': 'public, max-age=31536000' }
      });
    }

    if (path.startsWith('/assets/') && path.endsWith('.css')) {
      return new Response(cssContent, {
        headers: { 'Content-Type': 'text/css;charset=UTF-8', 'Cache-Control': 'public, max-age=31536000' }
      });
    }

    return new Response(indexHTML, {
      headers: { 'Content-Type': 'text/html;charset=UTF-8' }
    });
  }
};